    public static int winner(int[] a, int n, int k) {
        // If k is large enough, the original code simply returns n
        if (k >= n - 1) {
            return n;
        }
        int best = 0;
        int times = 0;
        for (int i = 0; i < n; i++) {
            if (a[i] > best) {
                best = a[i];
                if (i != 0) {
                    times = 1;
                }
            } else {
                times += 1;
            }
            if (times >= k) {
                return best;
            }
        }
        return best;
    }

