    public static int solveQuery(int start, int end, int[] arr) {
        Map<Integer, Integer> frequency = new HashMap<>();
        // Count frequencies in the given range [start, end]
        for (int i = start; i <= end; i++) {
            int value = arr[i];
            frequency.put(value, frequency.getOrDefault(value, 0) + 1);
        }
        // Count how many numbers appear exactly as many times as their value
        int count = 0;
        for (Map.Entry<Integer, Integer> entry : frequency.entrySet()) {
            if (entry.getKey().intValue() == entry.getValue()) {
                count++;
            }
        }
        return count;
    }

