    public static int calcAngle(double h, double m) {
        if (h < 0 || m < 0 || h > 12 || m > 60) {
            System.out.println("Wrong input");
        }
        // Handle edge cases where hands point exactly at 12 or 60
        if (h == 12) h = 0;
        if (m == 60) m = 0;
        int hourAngle   = (int) (0.5 * (h * 60 + m)); // 0.5 degrees per minute
        int minuteAngle = (int) (6 * m);              // 6 degrees per minute
        int angle = Math.abs(hourAngle - minuteAngle);
        angle = Math.min(360 - angle, angle);
        return angle;
    }

