    public static boolean isDivisible999(String num) {
        /* Special-case the value “0”. */
        if (num.length() == 1 && num.charAt(0) == '0') {
            return true;
        }
        int n = num.length();
        /* Pad to make length a multiple of 3. */
        if (n % 3 == 1) {
            num = "00" + num;
        } else if (n % 3 == 2) {
            num = "0" + num;
        }
        n = num.length();                 // length might have changed
        long groupSum = 0;                // may exceed int for very long inputs
        /* Sum the 3-digit groups.  */
        for (int i = 0; i < n; i++) {
            int group = 0;
            group += (num.charAt(i++) - '0') * 100;   // first digit of group
            group += (num.charAt(i++) - '0') * 10;    // second digit
            group +=  (num.charAt(i)  - '0');         // third digit
            groupSum += group;
        }
        /* If the sum is still large, recurse on the sum’s decimal representation. */
        if (groupSum > 1000) {
            return isDivisible999(Long.toString(groupSum));
        }
        /* Final test: the number is divisible by 999 iff the (reduced) sum is 999. */
        return groupSum == 999;
    }

