    public static boolean canRepresentBST(int[] pre, int n) {
        Stack<Integer> stack = new Stack<>();
        int root = Integer.MIN_VALUE;
        for (int i = 0; i < n; i++) {
            // If we find a node that is on the left side but smaller than
            // the allowed minimum (root), the sequence is invalid
            if (pre[i] < root) {
                return false;
            }
            // Nodes popped here are ancestors smaller than the current node.
            // The last popped value becomes the new root (lower bound).
            while (!stack.isEmpty() && stack.peek() < pre[i]) {
                root = stack.pop();
            }
            // Push the current key onto the stack
            stack.push(pre[i]);
        }
        return true;
    }

