    public static boolean checkDivisibility(String num) {
        int length = num.length();
        // Special-case: the number 0 is divisible by 13.
        if (length == 1 && num.charAt(0) == '0') {
            return true;
        }
        // Pad the string so its length becomes a multiple of 3.
        StringBuilder sb = new StringBuilder(num);
        if (length % 3 == 1) {
            sb.append("00");
            length += 2;
        } else if (length % 3 == 2) {
            sb.append('0');
            length += 1;
        }
        String str = sb.toString();
        int sum = 0;   // Running alternating sum of 3-digit groups
        int p   = 1;   // Alternates between +1 and −1
        for (int i = length - 1; i >= 0; i--) {
            int group = 0;
            // Units digit
            group += str.charAt(i--) - '0';
            // Tens digit
            group += (str.charAt(i--) - '0') * 10;
            // Hundreds digit
            group += (str.charAt(i)   - '0') * 100;
            sum += group * p;
            p *= -1;  // Flip the sign for the next group
        }
        sum = Math.abs(sum);
        return (sum % 13 == 0);
    }

