public static boolean check(String s1, String s2) {
    int n = s1.length();
    int m = s2.length();
    // dp[i][j] is true if the first i characters of s1 can be transformed
    // to match the first j characters of s2
    boolean[][] dp = new boolean[n + 1][m + 1];
    dp[0][0] = true;                          // empty strings match
    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= m; j++) {
            if (!dp[i][j]) continue;          // skip unreachable states
            // Option 1: Match current character (upper-casing s1[i] if needed)
            if (j < m && Character.toUpperCase(s1.charAt(i)) == s2.charAt(j)) {
                dp[i + 1][j + 1] = true;
            }
            // Option 2: Delete current character if it is lowercase
            if (!Character.isUpperCase(s1.charAt(i))) {
                dp[i + 1][j] = true;
            }
        }
    }
    return dp[n][m];
}

