    public static boolean checkReverse(int[] arr, int n) {
        if (n == 1) {
            return true;  // A single element is always “sorted”.
        }
        int i;
        // 1) Locate the first position where the ascending order breaks.
        for (i = 1; i < n && arr[i - 1] < arr[i]; i++) {
            // empty body on purpose
        }
        // If the whole array is already sorted, nothing to do.
        if (i == n) {
            return true;
        }
        // 2) 'j' marks the beginning of the possible segment to reverse.
        int j = i++;   // j = i; then increment i (post-increment behaviour).
        // 3) Move through the strictly decreasing segment.
        while (j < n && arr[j] < arr[j - 1]) {
            // If the current element is smaller than an element before the
            // start of the segment, reversing won’t fix the order.
            if (i > 1 && arr[j] < arr[i - 2]) {
                return false;
            }
            j++;
        }
        // If we consumed the entire array while in the decreasing run,
        // reversing that run would sort the array.
        if (j == n) {
            return true;
        }
        // 4) Verify that reversing will not break the ordering with the rest
        //    of the array.
        int k = j;
        if (arr[k] < arr[i - 1]) {
            return false;
        }
        // 5) Finally, the remaining part after the reversed segment must be
        //    in non-decreasing order.
        while (k > 1 && k < n) {
            if (arr[k] < arr[k - 1]) {
                return false;
            }
            k++;
        }
        return true;
    }

