    static boolean isRotated(String str1, String str2) {
        // Different lengths mean rotation is impossible
        if (str1.length() != str2.length()) {
            return false;
        }
        // For strings shorter than 2, a 2-position rotation
        // would bring the string back to itself
        if (str1.length() < 2) {
            return str1.equals(str2);
        }
        int len = str2.length();
        // Anti-clockwise rotation: last 2 chars move to the front
        String anticlockRot = str2.substring(len - 2) + str2.substring(0, len - 2);
        // Clockwise rotation: first 2 chars move to the end
        String clockRot = str2.substring(2) + str2.substring(0, 2);
        // Check if either rotation matches str1
        return str1.equals(clockRot) || str1.equals(anticlockRot);
    }

