static //  Assumes `MAX` is a predefined constant ≥ M.
//
//  dp is expected to be pre-filled with -1
//  (e.g. Arrays.fill(dp[i], -1) for every i).
static int isPossible(int n, int index, int modulo, int M,
                      int[] arr, int[][] dp) {
    // Make sure `modulo` is always in the range [0, M-1]
    modulo = ((modulo % M) + M) % M;
    // Base case: all elements have been considered
    if (index == n) {
        return (modulo == 0) ? 1 : 0;
    }
    // Memoised result already computed?
    if (dp[index][modulo] != -1) {
        return dp[index][modulo];
    }
    // Try adding the current element
    int placeAdd   = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
    // Try subtracting the current element
    int placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
    // If either path succeeds, store 1; otherwise store 0
    dp[index][modulo] = (placeAdd == 1 || placeMinus == 1) ? 1 : 0;
    return dp[index][modulo];
}

