    public static boolean isDivisible7(String numStr) {
        /* In the original C++ version an empty line (only ‘\n’) was treated
           as “0”, which is divisible by 7.  Re-create that behaviour.         */
        if (numStr == null || numStr.length() == 0 ||
           (numStr.length() == 1 && numStr.charAt(0) == '\n')) {
            return true;
        }
        /* We need a mutable sequence so we can append zeroes, something
           the C++ code did with strcat().                                     */
        StringBuilder num = new StringBuilder(numStr);
        int n = num.length();
        /* Pad with 0’s so the length is a multiple of 3. */
        if (n % 3 == 1) {
            num.append("00");
            n += 2;
        } else if (n % 3 == 2) {
            num.append('0');
            n += 1;
        }
        int gSum = 0;    // alternating sum of 3-digit groups
        int p    = 1;    // +1, −1, +1, …
        /* Process the string from right to left in groups of three digits. */
        for (int i = n - 1; i >= 0; i--) {
            int group = 0;
            group += num.charAt(i--) - '0';             // units
            group += (num.charAt(i--) - '0') * 10;      // tens
            group += (num.charAt(i)   - '0') * 100;     // hundreds
            gSum += group * p;
            p *= -1;   // flip the sign for the next group
        }
        /* Divisible by 7? */
        return gSum % 7 == 0;
    }

