    public static void spiralFill(int m, int n, int[][] a) {
        int val = 1;   // Value to be written next
        int k = 0;     // Starting row index
        int l = 0;     // Starting column index
        while (k < m && l < n) {
            // Fill the top row from left to right
            for (int i = l; i < n; ++i) {
                a[k][i] = val++;
            }
            k++;
            // Fill the rightmost column from top to bottom
            for (int i = k; i < m; ++i) {
                a[i][n - 1] = val++;
            }
            n--;
            // Fill the bottom row from right to left, if any remain
            if (k < m) {
                for (int i = n - 1; i >= l; --i) {
                    a[m - 1][i] = val++;
                }
                m--;
            }
            // Fill the leftmost column from bottom to top, if any remain
            if (l < n) {
                for (int i = m - 1; i >= k; --i) {
                    a[i][l] = val++;
                }
                l++;
            }
        }
    }

