    public static int nCrModp(int n, int r, int p) {
        // nCr is 0 when r > n
        if (r > n) return 0;
        // nCr == nC(n-r)
        if (r > n - r) r = n - r;
        int[] C = new int[r + 1];
        C[0] = 1;  // nC0 is always 1
        for (int i = 1; i <= n; i++) {
            // Compute next row of Pascal's Triangle from right to left
            for (int j = Math.min(i, r); j > 0; j--) {
                C[j] = (C[j] + C[j - 1]) % p;
            }
        }
        return C[r];
    }

