    public static String decimalToBinary(double num, int k_prec) {
        StringBuilder binary = new StringBuilder();
        // Extract integral part of num
        int integral = (int) num;
        // Extract fractional part of num
        double fractional = num - integral;
        /* Convert integral part to binary */
        if (integral == 0) {
            binary.append('0');
        } else {
            while (integral > 0) {
                int rem = integral % 2;
                binary.append((char) (rem + '0'));
                integral /= 2;
            }
            binary.reverse();   // The digits were generated in reverse order
        }
        binary.append('.');
        /* Convert fractional part to binary */
        while (k_prec-- > 0) {
            // Multiply fractional part by 2
            fractional *= 2;
            int fractBit = (int) fractional;
            if (fractBit == 1) {
                fractional -= fractBit;
                binary.append('1');
            } else {
                binary.append('0');
            }
        }
        return binary.toString();
    }

