    public static int countStrings(int n, int k) {
        // dp[i][j][b]:
        // i -> current length
        // j -> number of consecutive-1 pairs so far
        // b -> last placed bit (0 or 1)
        int[][][] dp = new int[n + 1][k + 1][2];
        // Base: length 1, zero consecutive pairs
        dp[1][0][0] = 1;   // "0"
        dp[1][0][1] = 1;   // "1"
        for (int i = 2; i <= n; i++) {
            for (int j = 0; j < i && j < k + 1; j++) {
                // Place '0' at the end ➜ no new pair formed
                dp[i][j][0] = dp[i - 1][j][0] + dp[i - 1][j][1];
                // Place '1' at the end
                dp[i][j][1] = dp[i - 1][j][0];               // last bit was 0 ➜ no new pair
                if (j - 1 >= 0) {
                    dp[i][j][1] += dp[i - 1][j - 1][1];      // last bit was 1 ➜ forms a new pair
                }
            }
        }
        return dp[n][k][0] + dp[n][k][1];
    }

