        for (int i = 0; i < n; i++) {
            dp[0][i] = 1;
        }
        // Build for all lengths 2..k
        for (int l = 1; l < k; l++) {
            for (int i = l; i < n; i++) {
                int count = 0;
                // Consider all previous positions j < i
                for (int j = l - 1; j < i; j++) {
