    public static int countPS(String str) {
        int n = str.length();
        if (n == 0) return 0;
        int[][] dp = new int[n][n];      // dp[i][j] stores count of palindromic substrings in str[i..j]
        boolean[][] P = new boolean[n][n]; // P[i][j] is true if str[i..j] is a palindrome
        // All single characters are palindromes
        for (int i = 0; i < n; i++) {
            P[i][i] = true;
        }
        // Check palindromes of length 2
        for (int i = 0; i < n - 1; i++) {
            if (str.charAt(i) == str.charAt(i + 1)) {
                P[i][i + 1] = true;
                dp[i][i + 1] = 1;
            }
        }
        // Check palindromes of length > 2
        for (int gap = 2; gap < n; gap++) {
            for (int i = 0; i < n - gap; i++) {
                int j = i + gap;
                if (str.charAt(i) == str.charAt(j) && P[i + 1][j - 1]) {
                    P[i][j] = true;
                }
                if (P[i][j]) {
                    dp[i][j] = dp[i][j - 1] + dp[i + 1][j] + 1 - dp[i + 1][j - 1];
                } else {
                    dp[i][j] = dp[i][j - 1] + dp[i + 1][j] - dp[i + 1][j - 1];
                }
            }
        }
        return dp[0][n - 1];
    }

