    public static int countPS(String str) {
        int N = str.length();
        // Extra row and column (+1) keep the translation faithful to the C++ code
        int[][] cps = new int[N + 1][N + 1];
        // Subsequences of length 1 (single characters) are palindromes
        for (int i = 0; i < N; i++) {
            cps[i][i] = 1;
        }
        // Build the table for all substring lengths L = 2 .. N
        for (int L = 2; L <= N; L++) {            // current substring length
            for (int i = 0; i <= N - L; i++) {    // starting index of substring
                int k = i + L - 1;                // ending index of substring
                // If characters match, add 1 plus counts of two subproblems
                if (str.charAt(i) == str.charAt(k)) {
                    cps[i][k] = cps[i][k - 1] + cps[i + 1][k] + 1;
                } else {
                    // If they don't match, use inclusion–exclusion principle
                    cps[i][k] = cps[i][k - 1] + cps[i + 1][k] - cps[i + 1][k - 1];
                }
            }
        }
        // The result for the whole string is stored at cps[0][N-1]
        return cps[0][N - 1];
    }

