    public static int countDecodingDP(String digits) {
        int n = digits.length();
        // An empty string or one starting with '0' has no valid decodings
        if (n == 0 || digits.charAt(0) == '0') {
            return 0;
        }
        int[] count = new int[n + 1];
        count[0] = 1;  // Empty string
        count[1] = 1;  // First character is guaranteed non-zero here
        for (int i = 2; i <= n; i++) {
            count[i] = 0;
            // Check single-digit decode possibility (current char not '0')
            if (digits.charAt(i - 1) > '0') {
                count[i] = count[i - 1];
            }
            // Check two-digit decode possibility (10–26 range)
            char prev = digits.charAt(i - 2);
            char curr = digits.charAt(i - 1);
            if (prev == '1' || (prev == '2' && curr < '7')) {
                count[i] += count[i - 2];
            }
        }
        return count[n];
    }

