    public static int findGroups(int[] arr) {
        int[] c = new int[3];   // c[0] → remainder 0, c[1] → remainder 1, c[2] → remainder 2
        // Count how many elements fall into each remainder class
        for (int value : arr) {
            c[value % 3]++;
        }
        int res = 0;
        // ---- Pairs ----
        // Both elements with remainder 0
        res += (c[0] * (c[0] - 1)) >> 1;   // nC2 for c[0]
        // One element with remainder 1 and one with remainder 2
        res += c[1] * c[2];
        // ---- Triplets ----
        // All three elements with the same remainder
        res += (c[0] * (c[0] - 1) * (c[0] - 2)) / 6;  // nC3 for c[0]
        res += (c[1] * (c[1] - 1) * (c[1] - 2)) / 6;  // nC3 for c[1]
        res += (c[2] * (c[2] - 1) * (c[2] - 2)) / 6;  // nC3 for c[2]
        // One element from each remainder class
        res += c[0] * c[1] * c[2];
        return res;
    }

