public static int countRotations(String n) {
    int len = n.length();
    // Handle single character strings
    if (len == 1) {
        int oneDigit = n.charAt(0) - '0';        // Convert char to its integer value
        return (oneDigit % 4 == 0) ? 1 : 0;
    }
    int count = 0;
    // Check every consecutive pair inside the string
    for (int i = 0; i < len - 1; i++) {
        int twoDigit = (n.charAt(i) - '0') * 10 + (n.charAt(i + 1) - '0');
        if (twoDigit % 4 == 0) {
            count++;
        }
    }
    // Finally, check the pair that wraps from the last digit back to the first
    int twoDigit = (n.charAt(len - 1) - '0') * 10 + (n.charAt(0) - '0');
    if (twoDigit % 4 == 0) {
        count++;
    }
    return count;
}

