    public static int countRotationsDivBy8(String n) {
        int len = n.length();
        int count = 0;
        // Case 1: single-digit number
        if (len == 1) {
            int oneDigit = n.charAt(0) - '0';
            return (oneDigit % 8 == 0) ? 1 : 0;
        }
        // Case 2: two-digit number
        if (len == 2) {
            int first  = (n.charAt(0) - '0') * 10 + (n.charAt(1) - '0');
            int second = (n.charAt(1) - '0') * 10 + (n.charAt(0) - '0');
            if (first  % 8 == 0) count++;
            if (second % 8 == 0) count++;
            return count;
        }
        // Case 3: length >= 3
        // All windows of length 3 inside the string
        for (int i = 0; i < len - 2; i++) {
            int threeDigit = (n.charAt(i) - '0') * 100
                           + (n.charAt(i + 1) - '0') * 10
                           + (n.charAt(i + 2) - '0');
            if (threeDigit % 8 == 0) count++;
        }
        // The two circular windows that wrap around the end of the string
        int threeDigit = (n.charAt(len - 1) - '0') * 100
                       + (n.charAt(0) - '0') * 10
                       + (n.charAt(1) - '0');
        if (threeDigit % 8 == 0) count++;
        threeDigit = (n.charAt(len - 2) - '0') * 100
                   + (n.charAt(len - 1) - '0') * 10
                   + (n.charAt(0) - '0');
        if (threeDigit % 8 == 0) count++;
        return count;
    }

