    public static int countSetBits(int n) {
        int i = 0;
        int ans = 0;
        while ((1 << i) <= n) {
            boolean k = false;        // current bit value to add (false -> 0, true -> 1)
            int change = 1 << i;      // how many numbers before toggling `k`
            for (int j = 0; j <= n; j++) {
                ans += k ? 1 : 0;     // add 1 if k == true
                if (change == 1) {
                    k = !k;           // toggle between 0 and 1
                    change = 1 << i;  // reset counter for this bit position
                } else {
                    --change;         // count down to next toggle
                }
            }
            ++i;                       // move to next bit position
        }
        return ans;
    }

