    public static String decode(String str) {
        Stack<Integer> integerStack = new Stack<>();
        Stack<Character> stringStack = new Stack<>();
        String temp   = "";
        String result = "";
        for (int i = 0; i < str.length(); i++) {
            int count = 0;
            /* 1. Current character is a digit, build the complete number */
            if (Character.isDigit(str.charAt(i))) {
                while (i < str.length() && Character.isDigit(str.charAt(i))) {
                    count = count * 10 + str.charAt(i) - '0';
                    i++;
                }
                i--;                       // Adjust because outer loop will ++
                integerStack.push(count);  // Push the repeat count
            }
            /* 2. Current character is a closing bracket ']' */
            else if (str.charAt(i) == ']') {
                temp  = "";
                count = 0;
                // Fetch the repeat count if available
                if (!integerStack.isEmpty()) {
                    count = integerStack.pop();
                }
                // Build the string inside the current brackets
                while (!stringStack.isEmpty() && stringStack.peek() != '[') {
                    temp = stringStack.pop() + temp;
                }
                // Pop the '[' from stack if present
                if (!stringStack.isEmpty() && stringStack.peek() == '[') {
                    stringStack.pop();
                }
                // Repeat the built string `count` times
                result = "";
                for (int j = 0; j < count; j++) {
                    result += temp;
                }
                // Push the expanded string back onto character stack
                for (int j = 0; j < result.length(); j++) {
                    stringStack.push(result.charAt(j));
                }
                result = "";
            }
            /* 3. Current character is an opening bracket '[' */
            else if (str.charAt(i) == '[') {
                // If the previous character is digit, simply push '['
                if (i > 0 && Character.isDigit(str.charAt(i - 1))) {
                    stringStack.push(str.charAt(i));
                }
                // Otherwise, this means implicit `1[ ... ]`
                else {
                    stringStack.push(str.charAt(i));
                    integerStack.push(1);
                }
            }
            /* 4. It's a normal alphabetic character, push to stack */
            else {
                stringStack.push(str.charAt(i));
            }
        }
        /* Pop everything left in the character stack to form the final result */
        while (!stringStack.isEmpty()) {
            result = stringStack.pop() + result;
        }
        return result;
    }

