    public static int discreteLogarithm(int a, int b, int m) {
        int n = (int) (Math.sqrt(m) + 1);
        /* pre-compute a^n (mod m) */
        long an = 1;
        for (int i = 0; i < n; ++i) {
            an = (an * a) % m;
        }
        /* store giant steps: (a^n)^i */
        Map<Integer, Integer> value = new HashMap<>();
        long cur = an;
        for (int i = 1; i <= n; ++i) {
            value.putIfAbsent((int) cur, i); // keep the first occurrence only
            cur = (cur * an) % m;
        }
        /* baby steps: b * a^i */
        cur = b;
        for (int i = 0; i <= n; ++i) {
            Integer j = value.get((int) cur);
            if (j != null) {
                int ans = j * n - i;
                if (ans < m) {
                    return ans;
                }
            }
            cur = (cur * a) % m;
        }
        return -1; // no solution
    }

