public static String longDivision(String number, int divisor) {
    StringBuilder ans = new StringBuilder();
    int idx  = 0;
    int temp = number.charAt(idx) - '0';
    // Collect digits from the left until `temp` becomes ≥ divisor
    while (temp < divisor && idx + 1 < number.length()) {
        temp = temp * 10 + (number.charAt(++idx) - '0');
    }
    // Perform long-division
    while (idx < number.length()) {
        // Current quotient digit
        ans.append((char) ((temp / divisor) + '0'));
        idx++;
        // Bring the next digit down (if any)
        if (idx < number.length()) {
            temp = (temp % divisor) * 10 + (number.charAt(idx) - '0');
        }
    }
    // If no quotient digits were produced, the result is 0
    if (ans.length() == 0) {
        return "0";
    }
    return ans.toString();
}

