    public static boolean isDivisibleBy12(String num) {
        int len = num.length();
        // For three or more digits we can use divisibility rules
        if (len >= 3) {
            // Last digit (units place)
            int d1 = num.charAt(len - 1) - '0';
            // If the number is odd, it cannot be divisible by 12 (needs to be even)
            if ((d1 & 1) == 1) {           // same as (d1 % 2 != 0)
                return false;
            }
            // Tens digit
            int d2 = num.charAt(len - 2) - '0';
            // Sum of all the digits (for the divisibility-by-3 rule)
            int digitSum = 0;
            for (int i = 0; i < len; i++) {
                digitSum += num.charAt(i) - '0';
            }
            // Last two-digit number (for the divisibility-by-4 rule)
            int lastTwo = d2 * 10 + d1;
            return (digitSum % 3 == 0) && (lastTwo % 4 == 0);
        }
        // For 1- or 2-digit numbers, simply parse and test
        int number = Integer.parseInt(num);
        return number % 12 == 0;
    }

