    public static boolean isDivisibleBy7(int num) {
        // Handle negative numbers by converting them to positive
        if (num < 0) {
            return isDivisibleBy7(-num);
        }
        // Base cases: 0 and 7 are divisible by 7
        if (num == 0 || num == 7) {
            return true;
        }
        // Single-digit numbers other than 7 are not divisible by 7
        if (num < 10) {
            return false;
        }
        // Recursive rule:
        // Remove the last digit, subtract twice the last digit, and recurse
        return isDivisibleBy7(num / 10 - 2 * (num - (num / 10) * 10));
    }

