    public static int eggDrop(int n, int k) {
        // eggFloor[i][j] will hold the result for i eggs and j floors
        int[][] eggFloor = new int[n + 1][k + 1];
        int res;
        /* 
         * We need 0 trials for 0 floors and 1 trial for 1 floor,
         * regardless of the number of eggs.
         */
        for (int i = 1; i <= n; i++) {
            eggFloor[i][0] = 0;
            eggFloor[i][1] = 1;
        }
        // With only one egg, trials = floors (worst-case: linear search)
        for (int j = 1; j <= k; j++) {
            eggFloor[1][j] = j;
        }
        /* Fill the rest of the entries in table using optimal substructure
         * property.
         */
        for (int i = 2; i <= n; i++) {
            for (int j = 2; j <= k; j++) {
                eggFloor[i][j] = Integer.MAX_VALUE;
                // Consider dropping from each floor x and take the minimum
                // over the worst-case of the two scenarios.
                for (int x = 1; x <= j; x++) {
                    res = 1 + Math.max(eggFloor[i - 1][x - 1],  // egg breaks
                                       eggFloor[i][j - x]);     // egg survives
                    if (res < eggFloor[i][j]) {
                        eggFloor[i][j] = res;
                    }
                }
            }
        }
        // eggFloor[n][k] holds the result we want
        return eggFloor[n][k];
    }

