public static int lps(String str) {
    if (str == null || str.isEmpty()) {
        return 0;
    }
    int n = str.length();
    int[][] L = new int[n][n];   // L[i][j] will hold the LPS length of str[i..j]
    // Strings of length 1 are palindromes of length 1
    for (int i = 0; i < n; i++) {
        L[i][i] = 1;
    }
    // Build the table. cl is the length of the substring
    for (int cl = 2; cl <= n; cl++) {
        for (int i = 0; i < n - cl + 1; i++) {
            int j = i + cl - 1;
            if (str.charAt(i) == str.charAt(j) && cl == 2) {
                L[i][j] = 2;
            } else if (str.charAt(i) == str.charAt(j)) {
                L[i][j] = L[i + 1][j - 1] + 2;
            } else {
                L[i][j] = Math.max(L[i][j - 1], L[i + 1][j]);
            }
        }
    }
    // The result is the LPS length for the whole string
    return L[0][n - 1];
}

