    public static int minPalPartition(String str) {
        if (str == null || str.length() == 0) {
            return 0;
        }
        int n = str.length();
        // C[i][j] stores the minimum cuts needed for substring str[i..j]
        int[][] C = new int[n][n];
        // P[i][j] is true if substring str[i..j] is a palindrome
        boolean[][] P = new boolean[n][n];
        // Every single character is a palindrome, no cuts needed
        for (int i = 0; i < n; i++) {
            P[i][i] = true;
            C[i][i] = 0;
        }
        // L is substring length
        for (int L = 2; L <= n; L++) {
            for (int i = 0; i < n - L + 1; i++) {
                int j = i + L - 1;  // Ending index of current substring
                if (L == 2) {
                    P[i][j] = (str.charAt(i) == str.charAt(j));
                } else {
                    P[i][j] = (str.charAt(i) == str.charAt(j)) && P[i + 1][j - 1];
                }
                if (P[i][j]) {
                    // No cut needed if str[i..j] itself is a palindrome
                    C[i][j] = 0;
                } else {
                    // Initialize with maximum value and try all possible cuts
                    C[i][j] = Integer.MAX_VALUE;
                    for (int k = i; k <= j - 1; k++) {
                        C[i][j] = Math.min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                    }
                }
            }
        }
        return C[0][n - 1];
    }

