    public static int findMinInsertions(char[] str, int l, int h) {
        // Invalid interval
        if (l > h) {
            return Integer.MAX_VALUE;
        }
        // Single character is already a palindrome
        if (l == h) {
            return 0;
        }
        // Two-character substring
        if (l == h - 1) {
            return (str[l] == str[h]) ? 0 : 1;
        }
        // If the end characters match, move inward
        if (str[l] == str[h]) {
            return findMinInsertions(str, l + 1, h - 1);
        }
        // If they don't match, consider both possibilities and take the minimum
        return Math.min(findMinInsertions(str, l, h - 1),
                        findMinInsertions(str, l + 1, h)) + 1;
    }

