    public static int countParenth(char[] symb, char[] oper, int n) {
        // DP tables: T[i][j] = #ways to make expression i..j TRUE
        //            F[i][j] = #ways to make expression i..j FALSE
        int[][] T = new int[n][n];
        int[][] F = new int[n][n];
        // Base cases: single symbols
        for (int i = 0; i < n; i++) {
            T[i][i] = (symb[i] == 'T') ? 1 : 0;
            F[i][i] = (symb[i] == 'F') ? 1 : 0;
        }
        // gap is length-1 of current subexpression
        for (int gap = 1; gap < n; gap++) {
            for (int i = 0, j = gap; j < n; i++, j++) {
                T[i][j] = 0;
                F[i][j] = 0;
                // Split the expression at every possible operator position k
                for (int g = 0; g < gap; g++) {
                    int k = i + g;
                    int tik = T[i][k] + F[i][k];       // total ways for left  part
                    int tkj = T[k + 1][j] + F[k + 1][j]; // total ways for right part
                    switch (oper[k]) {
                        case '&':
                            T[i][j] += T[i][k] * T[k + 1][j];
                            F[i][j] += tik * tkj - T[i][k] * T[k + 1][j];
                            break;
                        case '|':
                            F[i][j] += F[i][k] * F[k + 1][j];
                            T[i][j] += tik * tkj - F[i][k] * F[k + 1][j];
                            break;
                        case '^':
                            T[i][j] += F[i][k] * T[k + 1][j] + T[i][k] * F[k + 1][j];
                            F[i][j] += T[i][k] * T[k + 1][j] + F[i][k] * F[k + 1][j];
                            break;
                    }
                }
            }
        }
        return T[0][n - 1];
    }

