    public static int maxHamming(int[] arr) {
        int n = arr.length;
        if (n == 0) return 0;
        // Duplicate the array so that every rotation
        // can be represented as a sub-array of this long array.
        int[] brr = new int[2 * n];
        for (int i = 0; i < n; i++) {
            brr[i]     = arr[i];
            brr[n + i] = arr[i];
        }
        int maxHam = 0;
        // Try all rotations starting from 1 (rotation by 0 gives Hamming = 0).
        for (int i = 1; i < n; i++) {
            int currHam = 0;
            // Compare the rotation that starts at index i
            // (i … i + n - 1) with the original array (0 … n - 1).
            for (int j = i, k = 0; j < i + n; j++, k++) {
                if (brr[j] != arr[k]) {
                    currHam++;
                }
            }
            // If full Hamming distance is reached, it cannot get any higher.
            if (currHam == n) {
                return n;
            }
            maxHam = Math.max(maxHam, currHam);
        }
        return maxHam;
    }

