    public static boolean findDuplicateParenthesis(String str) {
        Stack<Character> stack = new Stack<>();
        for (char ch : str.toCharArray()) {
            // If current character is closing bracket
            if (ch == ')') {
                char top = stack.pop();
                int elementsInside = 0;
