            int place = 0;
            // Count elements ≤ mid using upperBound for each row
            for (int i = 0; i < r; i++) {
                place += upperBound(m[i], mid);
            }
            // Adjust search range based on the count
            if (place < desired) {
                min = mid + 1;
            } else {
                max = mid;
            }
