    public static int count(String a, String b) {
        int m = a.length();
        int n = b.length();
        // lookup[i][j] will hold the number of ways the first j characters of `b`
        // appear as a subsequence in the first i characters of `a`.
        int[][] lookup = new int[m + 1][n + 1];
        // If `b` is empty, there is exactly 1 subsequence of any prefix of `a` that matches it: the empty subsequence.
        for (int i = 0; i <= m; ++i) {
            lookup[i][0] = 1;
        }
        // If `a` is empty but `b` is not, no subsequences exist (already zero by default for row 0).
        for (int i = 1; i <= m; ++i) {
            for (int j = 1; j <= n; ++j) {
                if (a.charAt(i - 1) == b.charAt(j - 1)) {
                    // Match found: add the ways by including this char + ways by skipping it.
                    lookup[i][j] = lookup[i - 1][j - 1] + lookup[i - 1][j];
                } else {
                    // No match: only option is to skip current char of `a`.
                    lookup[i][j] = lookup[i - 1][j];
                }
            }
        }
        return lookup[m][n];
    }

