            }
        }
        /* 3) Accumulate result */
        int result = 0;
        // Sum |A[i][0]| for each row
        for (int i = 0; i < n; i++) {
            result += Math.abs(A[i][0]);
        }
        // Sum |A[0][j] - A[0][0]| for each column
        for (int j = 0; j < m; j++) {
            result += Math.abs(A[0][j] - A[0][0]);
        }
        return result;
    }

