    public static boolean isRectangle(int[][] matrix) {
        if (matrix == null || matrix.length == 0) {
            return false;
        }
        int rows    = matrix.length;
        int columns = matrix[0].length;
        // table[j] keeps the set of column indices k > j that have already formed
        // a pair (j, k) with value 1 in some previous row.
        Map<Integer, Set<Integer>> table = new HashMap<>();
        for (int i = 0; i < rows; ++i) {
            for (int j = 0; j < columns - 1; ++j) {
                if (matrix[i][j] != 1) {
                    continue;               // no need to check further if first corner isn't 1
                }
                for (int k = j + 1; k < columns; ++k) {
                    if (matrix[i][k] != 1) {
                        continue;           // second corner isn't 1
                    }
                    // Have we already seen this (j, k) pair in an earlier row?
                    if (table.containsKey(j) && table.get(j).contains(k)) {
                        return true;        // rectangle found
                    }
                    // Record the (j, k) pair for future rows.
                    table.computeIfAbsent(j, key -> new HashSet<>()).add(k);
                }
            }
        }
        return false;                       // no rectangle found
    }

