    public static int sumofFactors(int n) {
        // If n is odd, immediately return 0
        if (n % 2 != 0) {
            return 0;
        }
        int res = 1;
        // Iterate over possible prime factors
        for (int i = 2; i <= Math.sqrt(n); i++) {
            int count = 0;
            int currSum  = 1;
            int currTerm = 1;
            // While i divides n, update counters and sums
            while (n % i == 0) {
                count++;
                n /= i;
                // Special handling for the first factor 2
                if (i == 2 && count == 1) {
                    currSum = 0;
                }
                currTerm *= i;
                currSum  += currTerm;
            }
            res *= currSum;
        }
        // If n is still greater than 1, it is a remaining prime factor
        if (n >= 2) {
            res *= (1 + n);
        }
        return res;
    }

