    public static int evenSum(int n) {
        int[][] C = new int[n + 1][n + 1];
        // Build Pascal’s triangle up to the n-th row
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= i; j++) {        // j never exceeds i, and i ≤ n
                if (j == 0 || j == i) {
                    C[i][j] = 1;                   // First and last elements in the row are 1
                } else {
                    C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
                }
            }
        }
        // Sum the even-indexed coefficients in the n-th row
        int sum = 0;
        for (int i = 0; i <= n; i += 2) {
            sum += C[n][i];
        }
        return sum;
    }

