    public static int getSingle(int[] arr, int n) {
        int ones = 0;          // bits that have appeared once
        int twos = 0;          // bits that have appeared twice
        int commonBitMask;     // mask to clear bits that have appeared thrice
        for (int i = 0; i < n; i++) {
            // Add current bits to 'twos' if they've already appeared once in 'ones'
            twos |= ones & arr[i];
            // XOR will add bits to 'ones' that appear first time
            // and remove them if they appear second time
            ones ^= arr[i];
            // Bits that appear in both 'ones' and 'twos' are the bits
            // that have appeared three times. Clear those bits from both.
            commonBitMask = ~(ones & twos);
            ones &= commonBitMask;
            twos &= commonBitMask;
        }
        // 'ones' holds the unique element
        return ones;
    }

