        // Find the pivot point (the index of the largest element)
        int i;
        for (i = 0; i < n - 1; i++) {
            if (arr[i] > arr[i + 1]) {
                break;
            }
        }
        // l is index of the smallest element, r is index of the largest element
        int l = (i + 1) % n;
        int r = i;
        int cnt = 0;
        // Iterate until the two pointers meet
        while (l != r) {
            int currentSum = arr[l] + arr[r];
            if (currentSum == x) {
                cnt++;
                // If pointers are about to meet, exit
                if (l == (r - 1 + n) % n) {
                    return cnt;
                }
                // Move both pointers
                l = (l + 1) % n;
                r = (r - 1 + n) % n;
            } else if (currentSum < x) {
                // Move left pointer to increase sum
                l = (l + 1) % n;
            } else {  // currentSum > x
                // Move right pointer to decrease sum
                r = (r - 1 + n) % n;
            }
        }
        return cnt;
    }

