    public static boolean isSubSeqDivisible(String str) {
        int n = str.length();
        // dp[i][j] == 1  -> there exists a subsequence within the
        // first i characters whose value modulo 8 equals j
        int[][] dp = new int[n + 1][10];   // Java arrays are zero-initialised
        // Convert characters to separate digits (1-based indexing to mimic C++)
        int[] arr = new int[n + 1];
