        // Base case: for the first six keystrokes,
        // the optimal result is simply the number itself.
        if (N <= 6) {
            return N;
        }
        // Java requires arrays to be allocated with `new`.
        int[] screen = new int[N];
        // Initialize base values screen[0..5] = 1..6
        for (int n = 1; n <= 6; n++) {
            screen[n - 1] = n;
        }
        // Fill in the rest of the table using the recurrence
        for (int n = 7; n <= N; n++) {
            int option1 = 2 * screen[n - 4]; // Ctrl-A, Ctrl-C, Ctrl-V
            int option2 = 3 * screen[n - 5]; // Ctrl-A, Ctrl-C, Ctrl-V, Ctrl-V
            int option3 = 4 * screen[n - 6]; // Ctrl-A, Ctrl-C, Ctrl-V, Ctrl-V, Ctrl-V
            screen[n - 1] = Math.max(option1, Math.max(option2, option3));
        }
        return screen[N - 1];
