    public static int kthLargestSum(int[] arr, int n, int k) {
        /* ----------- Prefix-sum computation ----------- */
        int[] prefix = new int[n + 1];     // prefix[0] = 0 by default
        for (int i = 1; i <= n; i++) {
            prefix[i] = prefix[i - 1] + arr[i - 1];
        }
        /* ----------- Min-heap to keep k largest sums ----------- */
        PriorityQueue<Integer> pq = new PriorityQueue<>();   // min-heap
        /* ----------- Enumerate all sub-arrays ----------- */
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                int sum = prefix[j] - prefix[i - 1];
                if (pq.size() < k) {
                    pq.offer(sum);
                } else if (pq.peek() < sum) {
                    pq.poll();
                    pq.offer(sum);
                }
            }
        }
        return pq.peek();   // k-th largest sum
    }

