    public static void subsequence(char[] s, char[] t, int n, int k) {
        int last = 0;      // start index to scan in `s`
        int size = 0;      // current length of the subsequence being built
        int newLast = 0;   // remembers the last index where a chosen character was found
        for (char ch = 'z'; ch >= 'a'; ch--) {
            int cnt = 0;
            // Count occurrences of `ch` from position `last` to the end
            for (int i = last; i < n; i++) {
                if (s[i] == ch) {
                    cnt++;
                }
            }
            // If `ch` appears at least `k` times, append all its occurrences
            if (cnt >= k) {
                for (int i = last; i < n; i++) {
                    if (s[i] == ch) {
                        t[size++] = ch;
                        newLast = i;   // update the most recent index of `ch`
                    }
                }
                last = newLast;  // move the start index forward
            }
        }
        t[size] = '\0';  // null-terminate the destination array
    }

