static /**
 * Computes the previous lexicographical permutation of the characters
 * contained in the supplied StringBuilder.  The StringBuilder is modified
 * in-place.  
 *
 * @param str StringBuilder holding the characters to permute
 * @return true  if a previous permutation exists and has been produced  
 *         false if the given arrangement is already the first permutation
 */
public static boolean prevPermutation(StringBuilder str) {
    int n = str.length() - 1;
    /* Step 1: find the longest non-increasing suffix */
    int i = n;
    while (i > 0 && str.charAt(i - 1) <= str.charAt(i)) {
        i--;
    }
    if (i <= 0) {                 // already at first permutation
        return false;
    }
    /* Step 2: identify right-most element ≤ pivot (pivot = str[i-1]) */
    int j = i - 1;
    while (j + 1 <= n && str.charAt(j + 1) <= str.charAt(i - 1)) {
        j++;
    }
    /* Step 3: swap pivot with that element */
    char tmp = str.charAt(i - 1);
    str.setCharAt(i - 1, str.charAt(j));
    str.setCharAt(j, tmp);
    /* Step 4: reverse the suffix to obtain the largest ordering */
    for (int left = i, right = n; left < right; left++, right--) {
        tmp = str.charAt(left);
        str.setCharAt(left, str.charAt(right));
        str.setCharAt(right, tmp);
    }
    return true;
}

