    public static void minimizeWithKSwaps(int[] arr, int k) {
        int n = arr.length;
        for (int i = 0; i < n - 1 && k > 0; ++i) {
            int pos = i;
            // Find the smallest element within at most k distance from i
            for (int j = i + 1; j < n; ++j) {
                if (j - i > k) break;        // Can't move further than k
                if (arr[j] < arr[pos]) {
                    pos = j;
                }
            }
            // Bring the smallest element found to position i using adjacent swaps
            for (int j = pos; j > i; --j) {
                int temp = arr[j];
                arr[j] = arr[j - 1];
                arr[j - 1] = temp;
            }
            // Update remaining swap budget
            k -= (pos - i);
        }
    }

