    public static int lcs(int[][][] dp, int[] arr1, int n,
                          int[] arr2, int m, int k) {
        // Base cases
        if (k < 0) return NEG_INF;        // No more allowed changes
        if (n < 0 || m < 0) return 0;     // Reached the beginning of an array
        // Memoized result
        if (dp[n][m][k] != -1) {
            return dp[n][m][k];
        }
        // Option 1: skip an element from arr1
        int ans = Math.max(
                lcs(dp, arr1, n - 1, arr2, m, k),
                // Option 2: skip an element from arr2
                lcs(dp, arr1, n, arr2, m - 1, k)
        );
        // Option 3: match current elements if they are equal
        if (arr1[n - 1] == arr2[m - 1]) {
            ans = Math.max(ans,
                    1 + lcs(dp, arr1, n - 1, arr2, m - 1, k));
        }
        // Option 4: use one change (k-1) to match the current elements
        ans = Math.max(ans,
                1 + lcs(dp, arr1, n - 1, arr2, m - 1, k - 1));
        // Store and return
        dp[n][m][k] = ans;
        return ans;
    }

