                    len = lps[len - 1]; // fall back in the LPS array
                } else {
                    lps[i] = 0;
                    i++;
                }
            }
        }
        int res = lps[n - 1];
        return (res > n / 2) ? n / 2 : res;  // proper prefix & suffix must be < n/2 in length
