    public static String maximumPalinUsingKChanges(String str, int k) {
        // Work with character arrays for in-place modification.
        char[] original = str.toCharArray();   // Keeps the original characters for comparison.
        char[] palin    = str.toCharArray();   // Will hold the resulting palindrome.
        int l = 0;
        int r = str.length() - 1;
        // 1st pass: make the string a palindrome with minimum changes.
        while (l < r) {
            if (original[l] != original[r]) {
                // Replace both characters with the larger of the two.
                palin[l] = palin[r] = (char) Math.max(original[l], original[r]);
                k--;  // One change used.
            }
            l++;
            r--;
        }
        // If we used more changes than allowed, it's impossible.
        if (k < 0) {
            return "Not possible";
        }
        // 2nd pass: try to maximize the palindrome (turn digits into '9') while we still have changes left.
        l = 0;
        r = str.length() - 1;
        while (l <= r) {
            if (l == r) {   // Middle character in an odd-length string.
                if (k > 0) {
                    palin[l] = '9';
                }
            }
            // If current characters are not already '9', try to make them '9'.
            if (palin[l] < '9') {
                if (k >= 2 && palin[l] == original[l] && palin[r] == original[r]) {
                    // We haven't modified these positions before, need two changes.
                    k -= 2;
                    palin[l] = palin[r] = '9';
                } else if (k >= 1 && (palin[l] != original[l] || palin[r] != original[r])) {
                    // One of these positions was already changed in 1st pass, so only one extra change needed.
                    k--;
                    palin[l] = palin[r] = '9';
                }
            }
            l++;
            r--;
        }
        return new String(palin);
    }

