    public static int findMaxVal(int[] arr, int n, int num, int maxLimit) {
        // dp[ind][val] is true if we can obtain "val" after processing up to index "ind"
        boolean[][] dp = new boolean[n][maxLimit + 1];
        for (int ind = 0; ind < n; ind++) {
            for (int val = 0; val <= maxLimit; val++) {
                if (ind == 0) {
                    // Base case: only one element considered
                    dp[ind][val] = (num - arr[ind] == val) || (num + arr[ind] == val);
                } else {
                    boolean reachable = false;
                    // Check if we can reach current "val" by subtracting arr[ind]
                    if (val - arr[ind] >= 0) {
                        reachable |= dp[ind - 1][val - arr[ind]];
                    }
                    // Check if we can reach current "val" by adding arr[ind]
                    if (val + arr[ind] <= maxLimit) {
                        reachable |= dp[ind - 1][val + arr[ind]];
                    }
                    dp[ind][val] = reachable;
                }
            }
        }
        // Find the maximum reachable value ≤ maxLimit
        for (int val = maxLimit; val >= 0; val--) {
            if (dp[n - 1][val]) {
                return val;
            }
        }
        return -1; // No valid value found
    }

