    public static int maxCost(int[][] mat, int N) {
        // DP array: dp[i][j] holds max cost to reach cell (i, j)
        int[][] dp = new int[N][N];
        // Base cell
        dp[0][0] = mat[0][0];
        // Fill first column
        for (int i = 1; i < N; i++) {
            dp[i][0] = mat[i][0] + dp[i - 1][0];
        }
        // Fill the remaining cells respecting the triangular structure
        for (int i = 1; i < N; i++) {
            for (int j = 1; j < N && j < i + 1; j++) {
                dp[i][j] = mat[i][j] + Math.max(dp[i - 1][j - 1], dp[i - 1][j]);
            }
        }
        // Find maximum value in the last row
        int result = 0;
        for (int i = 0; i < N; i++) {
            result = Math.max(result, dp[N - 1][i]);
        }
        return result;
    }

