        int i = 0, j = 0;          // Current indices of ar1[] and ar2[]
        int m1 = -1, m2 = -1;      // Store the last two visited elements
        for (int count = 0; count <= n; count++) {
            // If all elements from ar1[] have been used
            if (i == n) {
                m1 = m2;
                m2 = ar2[0];
                break;
            }
            // If all elements from ar2[] have been used
            else if (j == n) {
                m1 = m2;
                m2 = ar1[0];
                break;
            }
            if (ar1[i] < ar2[j]) {
                m1 = m2;       // Store the previous median
                m2 = ar1[i];   // Update current median
                i++;
            } else {
                m1 = m2;
                m2 = ar2[j];
                j++;
            }
        }
        return (m1 + m2) / 2;
    }

