    public static int getMinDiff(int[] arr, int n, int k) {
        if (n == 1) return 0;
        Arrays.sort(arr);
        int ans   = arr[n - 1] - arr[0];
        int small = arr[0] + k;
        int big   = arr[n - 1] - k;
        if (small > big) {
            int tmp = small;
            small = big;
            big   = tmp;
        }
        for (int i = 1; i < n - 1; i++) {
            int subtract = arr[i] - k;
            int add      = arr[i] + k;
            // If either operation keeps the value within the [small, big] range,
            // no need to update the bounds.
            if (subtract >= small || add <= big) continue;
            // Otherwise, tighten whichever side yields the smaller span.
            if (big - subtract <= add - small) {
                small = subtract;
            } else {
                big = add;
            }
        }
        return Math.min(ans, big - small);
    }

