    public static int solve(char[] X, char[] Y,
                            int l, int r, int k,
                            int[][][] dp) {
        // Base cases
        if (k == 0) return 0;               // Nothing more to take
        if (l < 0 || r < 0) return INF;     // Out of bounds → invalid path
        // Memoised value?
        if (dp[l][r][k] != -1) return dp[l][r][k];
        // Cost of matching current characters
        int cost = (X[l] - 'a') ^ (Y[r] - 'a');
        // Three possibilities, just like in the C++ code
        int option1 = cost + solve(X, Y, l - 1, r - 1, k - 1, dp); // take both
        int option2 = solve(X, Y, l - 1, r, k, dp);                // skip X[l]
        int option3 = solve(X, Y, l, r - 1, k, dp);                // skip Y[r]
        // Store and return the minimum of the three
        dp[l][r][k] = Math.min(option1, Math.min(option2, option3));
        return dp[l][r][k];
    }

