    public static int minimumCost(int[] cost, int n, int W) {
        /*  Extract only the available packet sizes (cost[i] != -1)
         *  and store their weights (i + 1) and corresponding costs.
         */
        List<Integer> val = new ArrayList<>();
        List<Integer> wt  = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if (cost[i] != -1) {
                val.add(cost[i]);      // cost of this packet
                wt.add(i + 1);         // weight of this packet (1-based)
            }
        }
        n = val.size();                // updated number of usable packet types
        /*  DP table:
         *  minCost[i][j] = minimum cost to obtain exactly j kg
         *                  using the first i packet types (unbounded)
         */
        int[][] minCost = new int[n + 1][W + 1];
        // Initialize first row: using 0 packet types we cannot make any j > 0
        for (int j = 0; j <= W; j++) {
            minCost[0][j] = INF;
        }
        // Initialize first column: cost to make 0 kg is always 0
        for (int i = 1; i <= n; i++) {
            minCost[i][0] = 0;
        }
        // Fill DP table
        for (int i = 1; i <= n; i++) {
            int weight = wt.get(i - 1);
            int value  = val.get(i - 1);
            for (int j = 1; j <= W; j++) {
                if (weight > j) {
                    // Current packet too heavy, inherit value from previous row
                    minCost[i][j] = minCost[i - 1][j];
                } else {
                    // Either skip current packet or take it (unbounded knapsack)
                    int include = minCost[i][j - weight];
                    if (include != INF) {
                        include += value;
                    }
                    minCost[i][j] = Math.min(minCost[i - 1][j], include);
                }
            }
        }
        return (minCost[n][W] == INF) ? -1 : minCost[n][W];
    }

