    public static int smallestSubWithSum(int[] arr, int x) {
        int n = arr.length;
        int currSum = 0, minLen = n + 1;
        int start = 0, end = 0;
        while (end < n) {
            // Expand the window while the current sum is not yet greater than x
            while (currSum <= x && end < n) {
                // Reset if the current sum is non-positive and x is positive
                if (currSum <= 0 && x > 0) {
                    start = end;
                    currSum = 0;
                }
                currSum += arr[end++];
            }
            // Shrink the window from the left as long as the current sum exceeds x
            while (currSum > x && start < n) {
                if (end - start < minLen) {
                    minLen = end - start;
                }
                currSum -= arr[start++];
            }
        }
        return minLen;
    }

