    public static int minJumps(int[] arr, int n) {
        // Edge-case: empty array or first element is 0 (cannot move)
        if (n == 0 || arr[0] == 0) {
            return Integer.MAX_VALUE;
        }
        // jumps[i] will hold the minimum number of jumps
        // needed to reach position i from the start
        int[] jumps = new int[n];
        jumps[0] = 0;              // no jumps needed to stay at the first element
        // Build jumps[] in a bottom–up manner
        for (int i = 1; i < n; i++) {
            jumps[i] = Integer.MAX_VALUE;    // initial value (infinity)
            for (int j = 0; j < i; j++) {
                // Check if position i is reachable from j
                // and we already have a valid path to j
                if (i <= j + arr[j] && jumps[j] != Integer.MAX_VALUE) {
                    jumps[i] = Math.min(jumps[i], jumps[j] + 1);
                    break;  // Found the optimal previous jump for i
                }
            }
        }
        return jumps[n - 1];  // minimum jumps to reach the last index
    }

