    public static int minJumps(int[] arr, int n) {
        int[] jumps = new int[n];
        // Base case: we are already at the last element
        jumps[n - 1] = 0;
        // Build the jumps[] array from right to left
        for (int i = n - 2; i >= 0; i--) {
            // If element is 0, cannot move anywhere from here
            if (arr[i] == 0) {
                jumps[i] = Integer.MAX_VALUE;
            // If we can reach the end in one jump
            } else if (arr[i] >= n - i - 1) {
                jumps[i] = 1;
            // Otherwise, check all reachable positions and pick the minimum
            } else {
                int min = Integer.MAX_VALUE;
                for (int j = i + 1; j < n && j <= arr[i] + i; j++) {
                    if (min > jumps[j]) {
                        min = jumps[j];
                    }
                }
                jumps[i] = (min != Integer.MAX_VALUE) ? min + 1 : min;
            }
        }
        return jumps[0];
    }

