    public static int getMinSquares(int n) {
        if (n < 0) {
            throw new IllegalArgumentException("n must be non-negative");
        }
        // Handle small n directly
        if (n <= 3) {
            return n;
        }
        int[] dp = new int[n + 1];
        dp[0] = 0;
        dp[1] = 1;
        dp[2] = 2;
        dp[3] = 3;
        for (int i = 4; i <= n; i++) {
            // Maximum count is i (1² used i times)
            dp[i] = i;
            int root = (int) Math.sqrt(i);
            for (int x = 1; x <= root; x++) {
                int temp = x * x;
                // temp is always ≤ i by construction, so no need for an extra break
                dp[i] = Math.min(dp[i], 1 + dp[i - temp]);
            }
        }
        return dp[n];
    }

