    public static long minPerimeter(int n) {
        // Largest integer whose square is ≤ n
        int l = (int) Math.sqrt(n);
        int sq = l * l;
        // If n is a perfect square, the rectangle is a square (l x l)
        if (sq == n) {
            return 4L * l;         // perimeter = 4 * l
        } else {
            long row = n / l;       // other side length (integer division)
            long perimeter = 2L * (l + row);
            // If n is not divisible by l, one extra unit is needed on each side
            if (n % l != 0) {
                perimeter += 2;
            }
            return perimeter;
        }
    }

