    public static int minProductSubset(int[] a, int n) {
        // If the array contains only one element, return it.
        if (n == 1) {
            return a[0];
        }
        int maxNeg   = Integer.MIN_VALUE;  // Largest (closest-to-zero) negative number
        int minPos   = Integer.MAX_VALUE;  // Smallest positive number
        int countNeg = 0;                  // Number of negative elements
        int countZero = 0;                 // Number of zero elements
        int prod = 1;                      // Product of non-zero elements
        for (int i = 0; i < n; i++) {
            // If the current element is zero, just count it and continue
            if (a[i] == 0) {
                countZero++;
                continue;
            }
            // Track the largest negative number
            if (a[i] < 0) {
                countNeg++;
                maxNeg = Math.max(maxNeg, a[i]);
            }
            // Track the smallest positive number
            if (a[i] > 0) {
                minPos = Math.min(minPos, a[i]);
            }
            // Multiply non-zero elements into prod
            prod *= a[i];
        }
        // If all elements are zero, or there are zeros but no negatives
        if (countZero == n || (countNeg == 0 && countZero > 0)) {
            return 0;
        }
        // If no negative numbers, return the smallest positive number
        if (countNeg == 0) {
            return minPos;
        }
        // If count of negatives is even, exclude the one closest to zero
        if ((countNeg & 1) == 0) {
            prod /= maxNeg;
        }
        return prod;
    }

