    public static int minTimeForWritingChars(int N, int insert, int remove, int copy) {
        if (N == 0) return 0;
        if (N == 1) return insert;
        int[] dp = new int[N + 1];   // dp[0] is 0 by default
        for (int i = 1; i <= N; i++) {
            if (i % 2 == 0) {
                dp[i] = Math.min(dp[i - 1] + insert,     // insert one character
                                 dp[i / 2] + copy);       // copy the half-sized string
            } else {
                dp[i] = Math.min(dp[i - 1] + insert,      // insert one character
                                 dp[(i + 1) / 2] + copy + remove); // copy (i+1)/2 then remove one
            }
        }
