    public static void rearrange(int[] a, int size) {
        int positive = 0; // even index for non-negative numbers
        int negative = 1; // odd  index for non-positive numbers
        while (true) {
            // Move 'positive' forward until it finds a wrongly-placed negative number
            while (positive < size && a[positive] >= 0) {
                positive += 2;
            }
            // Move 'negative' forward until it finds a wrongly-placed positive number
            while (negative < size && a[negative] <= 0) {
                negative += 2;
            }
            // If both indices are within bounds, swap the misplaced elements
            if (positive < size && negative < size) {
                int temp = a[positive];
                a[positive] = a[negative];
                a[negative] = temp;
            } else {
                break; // no more elements to swap
            }
        }
    }

