    public static boolean isPrime(int p) {
        // 2^p − 1
        long checkNumber = (long) Math.pow(2, p) - 1;
        // First term of the Lucas-Lehmer sequence (mod checkNumber)
        long nextVal = 4 % checkNumber;
        // Generate the sequence p − 2 more times
        for (int i = 1; i < p - 1; i++) {
            nextVal = (nextVal * nextVal - 2) % checkNumber;
        }
        // If the last term is 0, the number is prime
        return nextVal == 0;
    }

