    public static void antiSpiralTraversal(int m, int n, int[][] a) {
        int k = 0;      // starting row index
        int l = 0;      // starting column index
        Stack<Integer> stk = new Stack<>();
        // Traverse the matrix in spiral manner but push the elements
        // on a stack so that we can print them in reverse (anti-spiral).
        while (k <= m && l <= n) {
            // 1. Traverse the first row from left to right.
            for (int i = l; i <= n; ++i) {
                stk.push(a[k][i]);
            }
            k++;
            // 2. Traverse the last column from top to bottom.
            for (int i = k; i <= m; ++i) {
                stk.push(a[i][n]);
            }
            n--;
            // 3. Traverse the last row from right to left, if any row left.
            if (k <= m) {
                for (int i = n; i >= l; --i) {
                    stk.push(a[m][i]);
                }
                m--;
            }
            // 4. Traverse the first column from bottom to top, if any column left.
            if (l <= n) {
                for (int i = m; i >= k; --i) {
                    stk.push(a[i][l]);
                }
                l++;
            }
        }
        // Pop all items from the stack to get anti-spiral order.
        while (!stk.isEmpty()) {
            System.out.print(stk.pop() + " ");
        }
    }

