    public static int findMaximum(int[] a, int n, int k) {
        Map<Integer, Integer> b = new HashMap<>();
        // First pass: compute the minimum distance (d) for each value x in the array
        for (int i = 0; i < n; i++) {
            int x = a[i];
            int d = Math.min(1 + i, n - i);  // distance from either end (1-based)
            b.merge(x, d, Math::min);        // store the smaller distance for each value
        }
        // Second pass: find the minimum (max(b[x], b[k-x])) among valid pairs
        int ans = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            int x = a[i];
            int y = k - x;
            if (x != y && b.containsKey(y)) {
                ans = Math.min(ans, Math.max(b.get(x), b.get(y)));
            }
        }
        return ans;
    }

