static /**
 * Validates whether the supplied string represents a valid ISBN-10.
 *
 * @param isbn the ISBN string to validate
 * @return true if the string is a valid ISBN-10, false otherwise
 */
public static boolean isValidISBN(String isbn) {
    int n = isbn.length();
    if (n != 10) {
        return false;                     // ISBN-10 must be exactly 10 characters
    }
    int sum = 0;
    // Process the first 9 digits
    for (int i = 0; i < 9; i++) {
        char ch = isbn.charAt(i);
        int digit = ch - '0';             // convert char to its numeric value
        if (digit < 0 || digit > 9) {
            return false;                 // non-digit encountered
        }
        sum += digit * (10 - i);          // weighted sum as per ISBN-10 spec
    }
    // Handle the last character, which can be a digit or 'X'
    char last = isbn.charAt(9);
    if (last != 'X' && (last < '0' || last > '9')) {
        return false;                     // invalid last character
    }
    sum += (last == 'X') ? 10 : (last - '0');
    // ISBN-10 is valid if sum is divisible by 11
    return sum % 11 == 0;
}

