    public static int breakSum(int n) {
        // Handle the trivial case
        if (n == 0) {
            return 0;
        }
        // Dynamic programming table
        int[] dp = new int[n + 1];
        // Base cases
        dp[0] = 0;
        if (n >= 1) {
            dp[1] = 1;
        }
        // Fill the table iteratively
        for (int i = 2; i <= n; i++) {
            dp[i] = Math.max(dp[i / 2] + dp[i / 3] + dp[i / 4], i);
        }
        return dp[n];
