    public static String simplify(String str) {
        int len = str.length();
        char[] res = new char[len];   // maximum possible length
        int index = 0;                // current position in the result array
        int i = 0;                    // current position in the input string
        Stack<Integer> s = new Stack<>();
        s.push(0);                    // 0 ⇒ keep sign, 1 ⇒ flip sign
        while (i < len) {
            char ch = str.charAt(i);
            if (ch == '+') {
                res[index++] = (s.peek() == 1) ? '-' : '+';
            } else if (ch == '-') {
