    public static int minRemovalsDP(int[] arr, int n) {
        int longestStart = -1;
        int longestEnd   = 0;
        for (int start = 0; start < n; start++) {
            int min = Integer.MAX_VALUE;
            int max = Integer.MIN_VALUE;
            for (int end = start; end < n; end++) {
                int val = arr[end];
                if (val < min) min = val;
                if (val > max) max = val;
                // Break if the current segment violates the condition
                if (2 * min <= max) break;
                // Update longest valid segment found so far
                if (longestStart == -1 || end - start > longestEnd - longestStart) {
                    longestStart = start;
                    longestEnd   = end;
                }
            }
        }
        // If no valid segment was found, all elements must be removed
        if (longestStart == -1) return n;
        // Elements to remove = total - length of longest valid segment
        return n - (longestEnd - longestStart + 1);
    }

