public static void sortArray(int[] arr, int n, int A, int B, int C) {
    // Apply quadratic transformation: A*x^2 + B*x + C
    for (int i = 0; i < n; i++) {
        arr[i] = A * arr[i] * arr[i] + B * arr[i] + C;
    }
    // Find the maximum value and its index
    int index = 0;
    int maximum = Integer.MIN_VALUE;
    for (int i = 0; i < n; i++) {
        if (maximum < arr[i]) {
            index = i;
            maximum = arr[i];
        }
    }
    int i = 0, j = n - 1;
    int[] newArr = new int[n];
    int k = 0;
    // Merge elements from both ends towards the maximum
    while (i < index && j > index) {
        if (arr[i] < arr[j]) {
            newArr[k++] = arr[i++];
        } else {
            newArr[k++] = arr[j--];
        }
    }
    // Copy any remaining elements on the left side of the maximum
    while (i < index) {
        newArr[k++] = arr[i++];
    }
    // Copy any remaining elements on the right side of the maximum
    while (j > index) {
        newArr[k++] = arr[j--];
    }
    // Place the maximum element at the end
    newArr[n - 1] = maximum;
    // Copy the sorted/transformed elements back to the original array
    System.arraycopy(newArr, 0, arr, 0, n);
}

