    public static int knapSack(int[] val, int[] wt, int n, int W) {
        // Two-row DP matrix; Java arrays are zero-initialised by default
        int[][] mat = new int[2][W + 1];
        for (int i = 0; i < n; i++) {
            if (i % 2 != 0) {                          // i is odd  → update row 1
                for (int j = 1; j <= W; j++) {
                    if (wt[i] <= j && j - wt[i] < W) {
                        mat[1][j] = Math.max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                    } else {
                        mat[1][j] = mat[0][j];
                    }
                }
            } else {                                   // i is even → update row 0
                for (int j = 1; j <= W; j++) {
                    if (wt[i] <= j && j - wt[i] < W) {
                        mat[0][j] = Math.max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                    } else {
                        mat[0][j] = mat[1][j];
                    }
                }
            }
        }
        // If n is odd, the result is in row 0; otherwise, in row 1
        return (n % 2 != 0) ? mat[0][W] : mat[1][W];
