    public static void stoogeSort(int[] arr, int l, int h) {
        if (l >= h) {
            return;
        }
        // Swap if the element at l is greater than the one at h
        if (arr[l] > arr[h]) {
            int temp = arr[l];
            arr[l] = arr[h];
            arr[h] = temp;
        }
        // If there are more than two elements, recursively sort
        if (h - l + 1 > 2) {
            int t = (h - l + 1) / 3;
            stoogeSort(arr, l, h - t);
            stoogeSort(arr, l + t, h);
            stoogeSort(arr, l, h - t);
        }
    }

