    public static boolean isSubsetSum(int[] arr, int n, int sum) {
        // DP table with only two rows to save space
        boolean[][] subset = new boolean[2][sum + 1];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= sum; j++) {
                if (j == 0) {
                    // Sum 0 can always be achieved with empty set
                    subset[i % 2][j] = true;
                } else if (i == 0) {
                    // With 0 elements (but positive desired sum), can't achieve any positive sum
                    subset[i % 2][j] = false;
                } else if (arr[i - 1] <= j) {
                    // Include or exclude current element
                    subset[i % 2][j] =
                            subset[(i + 1) % 2][j - arr[i - 1]] || subset[(i + 1) % 2][j];
                } else {
                    // Current element bigger than j, can't include it
                    subset[i % 2][j] = subset[(i + 1) % 2][j];
                }
            }
        }
        return subset[n % 2][sum];
    }

