    public static int binomialCoeffSum(int n) {
        int[][] C = new int[n + 1][n + 1];
        // Build Pascal's Triangle up to row n
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= i; j++) {  // j <= min(i, n) is equivalent to j <= i here
                if (j == 0 || j == i) {
                    C[i][j] = 1;                        // Base cases
                } else {
                    C[i][j] = C[i - 1][j - 1] + C[i - 1][j]; // Pascal's rule
                }
            }
        }
        // Sum the coefficients of the n-th row
        int sum = 0;
        for (int i = 0; i <= n; i++) {
            sum += C[n][i];
        }
        return sum;
    }

