    int result = 0;
    for (int i = 2; i <= Math.sqrt(n); i++) {
        if (n % i == 0) {
            if (i == n / i) {
                result += i;           // perfect square case
            } else {
                result += i + n / i;    // add both divisors
            }
        }
    }
    return result + n + 1;              // include 1 and the number itself
