public static int swapBits(int x, int p1, int p2, int n) {
    // Extract `n` bits starting at positions p1 and p2
    int set1 = (x >>> p1) & ((1 << n) - 1);
    int set2 = (x >>> p2) & ((1 << n) - 1);
    // XOR to identify differing bits
    int xor = set1 ^ set2;
    // Put the differing bits back to their original positions
    xor = (xor << p1) | (xor << p2);
    // Toggle the differing bits in the original number
    return x ^ xor;
}

