        int sum = 0;
        for (int i = 0; i < n; ++i) {
            int left = 0, right = 0;
            // Count strictly increasing sequence to the left of i
            for (int j = i - 1; j >= 0; --j) {
                if (templeHeight[j] < templeHeight[j + 1]) {
                    ++left;
                } else {
                    break;
                }
            }
            // Count strictly decreasing sequence to the right of i
            for (int j = i + 1; j < n; ++j) {
                if (templeHeight[j] < templeHeight[j - 1]) {
                    ++right;
                } else {
                    break;
                }
            }
            // Add the larger of left or right plus one for the current temple
            sum += Math.max(left, right) + 1;
        }
        return sum;
    }

