    public static int countTransformation(String a, String b) {
        int n = a.length();
        int m = b.length();
        // An empty target string can always be formed in exactly one way.
        if (m == 0) {
            return 1;
        }
        // dp[i][j] — number of ways to form b[0..i] using a[0..j]
        int[][] dp = new int[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = i; j < n; j++) {   // j starts from i to ensure enough chars in 'a'
                if (i == 0) {
                    if (j == 0) {
                        dp[i][j] = (a.charAt(j) == b.charAt(i)) ? 1 : 0;
                    } else if (a.charAt(j) == b.charAt(i)) {
                        dp[i][j] = dp[i][j - 1] + 1;
                    } else {
                        dp[i][j] = dp[i][j - 1];
                    }
                } else {
                    if (a.charAt(j) == b.charAt(i)) {
                        dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1];
                    } else {
                        dp[i][j] = dp[i][j - 1];
                    }
                }
            }
        }
        return dp[m - 1][n - 1];
    }

