    public static int isMultipleOf3(int n) {
        int oddCount  = 0;
        int evenCount = 0;
        // Make n positive
        if (n < 0) n = -n;
        // Base cases
        if (n == 0) return 1; // true
        if (n == 1) return 0; // false
        // Count set bits at odd and even positions
        while (n != 0) {
            if ((n & 1) != 0) oddCount++;      // bit at position 0 (LSB)
            if ((n & 2) != 0) evenCount++;     // bit at position 1
            n >>= 2;                           // drop two bits
        }
        // Recurse with the absolute difference of the counts
        return isMultipleOf3(Math.abs(oddCount - evenCount));
    }

